fn collatz_len(n: i64) -> i64 = {
    let mut current = n;
    let mut length = 1;
    while current != 1 {
        if current % 2 == 0 {
            current = current / 2
        } else {
            current = 3 * current + 1
        };
        length = length + 1
    };
    length
};

